import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Waymo vs Uber：自动驾驶技术窃密诉讼（2017）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/cases/ip/waymo-uber.md","filePath":"zh/cases/ip/waymo-uber.md"}'),l={name:"zh/cases/ip/waymo-uber.md"};function i(s,t,n,d,h,b){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="waymo-vs-uber-自动驾驶技术窃密诉讼-2017" tabindex="-1">Waymo vs Uber：自动驾驶技术窃密诉讼（2017） <a class="header-anchor" href="#waymo-vs-uber-自动驾驶技术窃密诉讼-2017" aria-label="Permalink to &quot;Waymo vs Uber：自动驾驶技术窃密诉讼（2017）&quot;">​</a></h1><p><strong>离职员工带走14,000份机密文件</strong></p><blockquote><p><strong>关联指南：</strong> <a href="/zh/ip-guide.html">知识产权保护与防伪打假指南</a> · <strong>适用行业：</strong> 科技、自动驾驶、创业并购</p></blockquote><hr><h2 id="事件概述" tabindex="-1">事件概述 <a class="header-anchor" href="#事件概述" aria-label="Permalink to &quot;事件概述&quot;">​</a></h2><p>2017年2月，Waymo（Google/Alphabet旗下自动驾驶公司）起诉 Uber，指控前 Waymo 工程师安东尼·莱万多夫斯基（Anthony Levandowski）在离职前秘密下载了超过<strong>14,000份机密文件</strong>，随后创立自动驾驶卡车公司 Otto，并被 Uber 以6.8亿美元收购——Waymo 认为 Uber 此举是为了获取 Waymo 的激光雷达（LiDAR）技术机密。</p><hr><h2 id="事件时间线" tabindex="-1">事件时间线 <a class="header-anchor" href="#事件时间线" aria-label="Permalink to &quot;事件时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>事件</th></tr></thead><tbody><tr><td>2016年1月</td><td>莱万多夫斯基从 Waymo/Google 辞职</td></tr><tr><td>2016年1月（辞职前数周）</td><td>从 Waymo 内网下载14,000份技术文件至个人设备</td></tr><tr><td>2016年2月</td><td>与前同事共同创立 Otto（自动驾驶卡车公司）</td></tr><tr><td>2016年8月</td><td>Uber 以6.8亿美元现金+股票收购 Otto</td></tr><tr><td>2017年2月</td><td>Waymo 提起诉讼，指控专利侵权与商业秘密盗窃</td></tr><tr><td>2018年2月</td><td>双方庭前和解：Uber 向 Waymo 支付约<strong>2.45亿美元</strong>价值的 Uber 股权</td></tr><tr><td>2019年</td><td>美国司法部对莱万多夫斯基提起刑事指控</td></tr><tr><td>2020年</td><td>莱万多夫斯基认罪，被判处<strong>18个月监禁</strong>（新冠疫情期间改为居家监禁）</td></tr></tbody></table><hr><h2 id="核心争议-激光雷达-lidar-技术" tabindex="-1">核心争议：激光雷达（LiDAR）技术 <a class="header-anchor" href="#核心争议-激光雷达-lidar-技术" aria-label="Permalink to &quot;核心争议：激光雷达（LiDAR）技术&quot;">​</a></h2><p>Waymo 指控 Uber 使用了其专有的 LiDAR 电路板设计，具体表现为：</p><ul><li>Uber 在 Otto 收购后，迅速推出了一款内部 LiDAR 系统，其电路板设计与 Waymo 的专利设计高度相似</li><li>Waymo 工程师在行业会议上见到 Uber 设备时，认出了自己曾设计的独特组件结构</li></ul><p>LiDAR 是自动驾驶技术的核心传感器，顶尖 LiDAR 系统的研发成本高达数亿美元，是 Waymo 多年技术积累的核心资产。</p><hr><h2 id="uber-的尽职调查责任" tabindex="-1">Uber 的尽职调查责任 <a class="header-anchor" href="#uber-的尽职调查责任" aria-label="Permalink to &quot;Uber 的尽职调查责任&quot;">​</a></h2><p>本案的关键法律问题之一：<strong>Uber 在收购 Otto 时，是否尽到了充分的尽职调查义务？</strong></p><h3 id="已知的红旗信号" tabindex="-1">已知的红旗信号 <a class="header-anchor" href="#已知的红旗信号" aria-label="Permalink to &quot;已知的红旗信号&quot;">​</a></h3><p>在 Uber 完成收购时，有几个明显的警示信号：</p><ol><li>Otto 成立仅6个月，几乎没有独立研发记录，却声称拥有完整的 LiDAR 技术</li><li>Otto 的核心团队全部来自 Waymo/Google，且都在短时间内集体离职</li><li>莱万多夫斯基曾明确告诉 Uber CEO Travis Kalanick，他需要在收购前&quot;拿走一些东西&quot;（据Waymo方证词）</li></ol><h3 id="uber-的立场" tabindex="-1">Uber 的立场 <a class="header-anchor" href="#uber-的立场" aria-label="Permalink to &quot;Uber 的立场&quot;">​</a></h3><p>Uber 声称：</p><ul><li>收购前已做了IP尽职调查</li><li>不知道莱万多夫斯基带走了 Waymo 的文件</li><li>已要求莱万多夫斯基签署声明，确认没有使用前雇主的IP</li></ul><p>法院认为：这些措施远不足够，Uber 存在&quot;选择性失明&quot;（willful blindness）。</p><hr><h2 id="并购中的ip尽职调查教训" tabindex="-1">并购中的IP尽职调查教训 <a class="header-anchor" href="#并购中的ip尽职调查教训" aria-label="Permalink to &quot;并购中的IP尽职调查教训&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Waymo vs Uber 对并购IP尽职调查的启示</p><p>这是并购、收购初创公司、或招募竞争对手关键人才时的必读案例。</p><p><strong>人才与IP风险的关联性：</strong></p><ul><li>招募来自直接竞争对手的核心技术人员，须评估其是否携带了前雇主的IP</li><li>要求候选人/收购标的团队提供&quot;洁净室承诺&quot;——即证明新开发工作与前雇主IP无关</li><li>法律顾问须审查候选人在前东家签署的竞业协议（Non-Compete）和保密协议（NDA）</li></ul><p><strong>收购尽职调查中的IP核查：</strong></p><ul><li>要求目标公司的核心技术团队列出其知识产权来源（自主研发 vs 外部获取）</li><li>对核心技术人员进行个人访谈，核查其在前雇主的职责与当前技术之间的重叠度</li><li>聘请独立技术专家比对目标公司技术与行业已知IP的相似性</li></ul><p><strong>合同保护：</strong></p><ul><li>收购合同中须包含IP陈述与保证（Representations &amp; Warranties）</li><li>买方须在交割后对关键员工实施<strong>新的保密协议</strong>，约束其不得使用前雇主IP</li><li>在收购协议中加入IP清洁承诺条款（IP Clean Room Covenant）</li></ul></div><hr><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>Waymo LLC v. Uber Technologies Inc. — 案件文件（N.D. Cal. 2017）</li><li>The New York Times: <em>Anthony Levandowski&#39;s Guilty Plea</em> (2020)</li><li><em>Driven: The Race to Create the Autonomous Car</em> — Alex Davies (2021)</li><li>Harvard Business School Case: <em>Waymo v. Uber</em> (2018)</li></ul>',30)])])}const p=a(l,[["render",i]]);export{m as __pageData,p as default};
